/**
 * Loaders for pre-built graph artifacts.
 * These are JSON files generated by scripts/build-graph.ts
 * and committed to src/data/generated/.
 *
 * Astro can import JSON natively; these helpers wrap the imports
 * with types and provide a consistent interface.
 */
import type { ContentGraph, RelationIndex, TaxonomyIndex, GovernanceIndex } from '../graph/types';

// Astro supports static JSON imports at build time
// In scripts (Node context), we use require/readFileSync instead

function isAstroContext(): boolean {
  // Heuristic: in Astro build context, import.meta is available
  try {
    return typeof import.meta !== 'undefined' && typeof import.meta.env !== 'undefined';
  } catch {
    return false;
  }
}

let _graph: ContentGraph | null = null;
let _relations: RelationIndex | null = null;
let _taxonomy: TaxonomyIndex | null = null;
let _governance: GovernanceIndex | null = null;

function loadJson<T>(relativePath: string): T {
  // In Node script context, use require
  if (typeof require !== 'undefined') {
    const { join } = require('path');
    const { readFileSync } = require('fs');
    const abs = join(process.cwd(), relativePath);
    return JSON.parse(readFileSync(abs, 'utf8')) as T;
  }
  throw new Error(`Cannot load ${relativePath} — no require available. Use dynamic import instead.`);
}

export async function loadContentGraph(): Promise<ContentGraph> {
  if (_graph) return _graph;
  try {
    const mod = await import('../../data/generated/content-graph.json');
    _graph = (mod.default ?? mod) as ContentGraph;
    return _graph;
  } catch {
    _graph = loadJson<ContentGraph>('src/data/generated/content-graph.json');
    return _graph;
  }
}

